BEGIN; CREATE OR REPLACE FUNCTION public.normalize_delivery_plan_customer_v1() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$ DECLARE v_product_customer_id uuid; v_delivery_parent_id uuid; BEGIN IF TG_OP = 'INSERT' OR (COALESCE(OLD.actual_qty, 0) = 0 AND COALESCE(OLD.is_completed, false) = false) THEN SELECT p.customer_id INTO v_product_customer_id FROM public.products p WHERE p.id = NEW.product_id AND p.deleted_at IS NULL; IF v_product_customer_id IS NULL THEN RAISE EXCEPTION 'Ma hang khong co khach hang hien tai.'; END IF; IF NEW.delivery_customer_id IS NOT NULL AND NEW.delivery_customer_id IS DISTINCT FROM v_product_customer_id THEN SELECT c.parent_customer_id INTO v_delivery_parent_id FROM public.customers c WHERE c.id = NEW.delivery_customer_id AND c.deleted_at IS NULL; IF NOT FOUND OR v_delivery_parent_id IS DISTINCT FROM v_product_customer_id THEN RAISE EXCEPTION 'Diem giao khong thuoc khach hang hien tai cua ma hang.'; END IF; END IF; NEW.customer_id := v_product_customer_id; END IF; RETURN NEW; END; $$; DROP TRIGGER IF EXISTS trg_normalize_delivery_plan_customer_v1 ON public.delivery_plans; CREATE TRIGGER trg_normalize_delivery_plan_customer_v1 BEFORE INSERT OR UPDATE ON public.delivery_plans FOR EACH ROW EXECUTE FUNCTION public.normalize_delivery_plan_customer_v1(); CREATE OR REPLACE FUNCTION public.normalize_delivery_transaction_customer_v1() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$ DECLARE v_product_customer_id uuid; v_plan_delivery_customer_id uuid; v_delivery_parent_id uuid; BEGIN IF NEW.delivery_plan_id IS NULL THEN RETURN NEW; END IF; SELECT p.customer_id, dp.delivery_customer_id INTO v_product_customer_id, v_plan_delivery_customer_id FROM public.delivery_plans dp JOIN public.products p ON p.id = dp.product_id AND p.deleted_at IS NULL WHERE dp.id = NEW.delivery_plan_id AND dp.deleted_at IS NULL AND dp.product_id = NEW.product_id; IF NOT FOUND OR v_product_customer_id IS NULL THEN RAISE EXCEPTION 'Khong xac dinh duoc khach hang hien tai cua dong giao hang.'; END IF; IF v_plan_delivery_customer_id IS NOT NULL AND v_plan_delivery_customer_id IS DISTINCT FROM v_product_customer_id THEN SELECT c.parent_customer_id INTO v_delivery_parent_id FROM public.customers c WHERE c.id = v_plan_delivery_customer_id AND c.deleted_at IS NULL; IF NOT FOUND OR v_delivery_parent_id IS DISTINCT FROM v_product_customer_id THEN RAISE EXCEPTION 'Diem giao khong thuoc khach hang hien tai cua ma hang.'; END IF; END IF; NEW.customer_id := v_product_customer_id; NEW.delivery_customer_id := v_plan_delivery_customer_id; RETURN NEW; END; $$; DROP TRIGGER IF EXISTS trg_normalize_delivery_transaction_customer_v1 ON public.inventory_transactions; CREATE TRIGGER trg_normalize_delivery_transaction_customer_v1 BEFORE INSERT ON public.inventory_transactions FOR EACH ROW EXECUTE FUNCTION public.normalize_delivery_transaction_customer_v1(); CREATE OR REPLACE FUNCTION public.sync_delivery_backlog(p_plan_id uuid) RETURNS void LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$ DECLARE v_plan record; v_target_id uuid; v_debt numeric := 0; v_tomorrow date; v_actor uuid; v_key uuid; v_force_backlog boolean := false; v_current_customer_id uuid; v_delivery_parent_id uuid; BEGIN SELECT dp.*, p.customer_id AS current_customer_id INTO v_plan FROM public.delivery_plans dp JOIN public.products p ON p.id = dp.product_id AND p.deleted_at IS NULL WHERE dp.id = p_plan_id AND dp.deleted_at IS NULL FOR UPDATE OF dp; IF NOT FOUND THEN RETURN; END IF; v_current_customer_id := v_plan.current_customer_id; IF v_current_customer_id IS NULL THEN RAISE EXCEPTION 'Ma hang khong co khach hang hien tai.'; END IF; IF v_plan.delivery_customer_id IS NOT NULL AND v_plan.delivery_customer_id IS DISTINCT FROM v_current_customer_id THEN SELECT c.parent_customer_id INTO v_delivery_parent_id FROM public.customers c WHERE c.id = v_plan.delivery_customer_id AND c.deleted_at IS NULL; IF NOT FOUND OR v_delivery_parent_id IS DISTINCT FROM v_current_customer_id THEN RAISE EXCEPTION 'Diem giao khong thuoc khach hang hien tai cua ma hang.'; END IF; END IF; v_actor := COALESCE(v_plan.updated_by, v_plan.created_by, auth.uid()); v_tomorrow := v_plan.plan_date + 1; v_key := public.delivery_point_key(v_current_customer_id, v_plan.delivery_customer_id); v_force_backlog := COALESCE(current_setting('app.force_delivery_backlog_sync', true) = 'on', false); IF v_force_backlog OR COALESCE(v_plan.actual_qty, 0) > 0 OR COALESCE(v_plan.is_completed, false) = true THEN v_debt := GREATEST(0, (COALESCE(v_plan.planned_qty, 0) + COALESCE(v_plan.backlog_qty, 0)) - COALESCE(v_plan.actual_qty, 0)); END IF; SELECT id INTO v_target_id FROM public.delivery_plans WHERE plan_date = v_tomorrow AND product_id = v_plan.product_id AND public.delivery_point_key(customer_id, delivery_customer_id) = v_key AND deleted_at IS NULL FOR UPDATE; IF v_debt > 0 THEN IF v_target_id IS NULL THEN INSERT INTO public.delivery_plans (plan_date, product_id, customer_id, delivery_customer_id, planned_qty, backlog_qty, is_backlog, note, note_2, created_by, updated_by) VALUES (v_tomorrow, v_plan.product_id, v_current_customer_id, v_plan.delivery_customer_id, 0, v_debt, true, NULL, NULL, v_actor, v_actor); ELSE UPDATE public.delivery_plans SET customer_id = v_current_customer_id, backlog_qty = v_debt, is_backlog = true, updated_at = now(), updated_by = v_actor WHERE id = v_target_id; END IF; ELSIF v_target_id IS NOT NULL THEN UPDATE public.delivery_plans SET backlog_qty = 0, is_backlog = false, updated_at = now(), updated_by = v_actor WHERE id = v_target_id; UPDATE public.delivery_plans SET deleted_at = now(), deleted_by = v_actor, updated_at = now(), updated_by = v_actor WHERE id = v_target_id AND COALESCE(planned_qty, 0) = 0 AND COALESCE(backlog_qty, 0) = 0 AND COALESCE(actual_qty, 0) = 0; END IF; END; $$; UPDATE public.delivery_plans dp SET customer_id = p.customer_id, updated_at = now() FROM public.products p WHERE p.id = dp.product_id AND p.deleted_at IS NULL AND p.customer_id IS NOT NULL AND dp.deleted_at IS NULL AND dp.delivery_customer_id IS NULL AND COALESCE(dp.actual_qty, 0) = 0 AND COALESCE(dp.is_completed, false) = false AND dp.customer_id IS DISTINCT FROM p.customer_id AND NOT EXISTS (SELECT 1 FROM public.delivery_plans current_dp WHERE current_dp.id <> dp.id AND current_dp.deleted_at IS NULL AND current_dp.plan_date = dp.plan_date AND current_dp.product_id = dp.product_id AND current_dp.delivery_customer_id IS NULL AND current_dp.customer_id = p.customer_id); NOTIFY pgrst, 'reload schema'; COMMIT;
